var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"……숙주가 멀쩡하잖아? 일처리를 왜 이딴 식으로 한 거지?","JPN":"……宿主が生きてんじゃないか？\\nお前ら、ちゃんと仕事する気はあるのか？","ENG":"Huh? The host is still alive? Is this the best you can do?","TWN":"……宿主怎麼還好好的？你們是怎麼處理事情的？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지금 일이 문제야?","JPN":"仕事なんてどうでもいい！","ENG":"The job is not what’s important right now!","TWN":"現在重點是這個嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"쟤는 내 친구야! 리온이라고! 너희들이 죽었다고 했던!","JPN":"あの子は私の友達だ！　リオンなんだよ！\\nあんたたちが死んだって言ってた！","ENG":"She’s my friend! That’s Liona! The one you guys said had died!","TWN":"她是我的朋友，萊恩！就是你們說她已經死掉的那個！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"멀쩡히 살아 있는 애를 왜 죽었다고 한 거야?!","JPN":"元気に生きている子を、どうして死んだと言ったんだ！？","ENG":"Why did you tell us that she died when she’s clearly alive?!","TWN":"她明明就活得好好的，你們為什麼說她死掉了？！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"위에서도 다 생각이 있어서 그랬겠지. 그래야 너희를 다루기 편하다던가.","JPN":"上に何か事情があったからだろ。\\nそれでお前らが扱いやすくなるとか。","ENG":"I’m pretty sure that top brass had their reasons. Like, to make you guys easier to manipulate.","TWN":"上面當然有他們的想法！譬如說這樣比較好控制你們？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……뭐라고?","JPN":"……何だと？","ENG":"...What?","TWN":"……你說什麼？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"현장에 도착했다.","JPN":"現場に到着した。","ENG":"We’re at the location.","TWN":"我們已抵達現場。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"현재 <color=#ffd34c>기생체</color>도, 숙주도 멀쩡한 걸로 보아 싸움이 이뤄지지 않은 상황이다.","JPN":"現在<color=#ffd34c>寄生体</color>も宿主も正常なことから、戦闘は行われていない状況だ。","ENG":"Seeing that both <color=#ffd34c>the parasite</color> and the host are in good shape, it seems that there wasn’t a fight.","TWN":"目前<color=#ffd34c>寄生物</color>和宿主都安然無恙，看來是還沒行動。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"……알겠다.","JPN":"……了解。","ENG":"...Understood.","TWN":"……是。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"숙주와 오즈까지 모두 제압하라는 명령이다.","JPN":"宿主とオズ、全員制圧しろとの命令だ。","ENG":"Our orders are to apprehend both the host and OZ.","TWN":"上面下令，制伏宿主和奧茲國！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"반항하면 블랙박스만 가져오라는군. 데이터가 필요한가 봐.","JPN":"反抗するようならブラックボックスだけ持ち帰って来いだと。データが必要らしい。","ENG":"If they resist, we only need to bring back the black box. It seems like they need the data.","TWN":"反抗的話，就把黑盒子帶回去就好！上面需要裡面的資料！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"들었지? 그러게 일 좀 잘하지 그랬냐.","JPN":"聞いたか？　だからちゃんと仕事すればよかったのにな。","ENG":"You heard that? You should have done the job properly.","TWN":"你看吧？誰叫你們不把事情辦好！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"무슨 개소리들이야?","JPN":"何を言ってるんだ？","ENG":"What kind of crap is this?","TWN":"你在胡說什麼？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"몰랐다는 게 신기하네. 마지막 심부름이라고 그러지 않았어?","JPN":"まだ気づいてないのか。最後のお使いって言われただろ？","ENG":"I’m surprised you didn’t know. Weren’t you told that this is your last errand?","TWN":"你到現在還搞不清楚嗎？不是說了是\\"最後的任務\\"？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그게 무슨 상관인데!","JPN":"それと何の関係があるんだよ！","ENG":"What does that have to do with this?!","TWN":"現在是什麼情況？！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"하하, 설마 마지막 심부름을 마치면 졸업식이라도 열어 줄 줄 알았어?","JPN":"ハハ、まさか最後のお使いが終わったら、\\n卒業式でも開いてもらえると思ったのか？","ENG":"Haha, were you expecting a graduation party after you finished your last errand?","TWN":"哈哈，你該不會以為辦完最後的任務後，上面還會替你辦畢業典禮吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}}]`);export{e as default};